import{_ as e,o as a,c as r,a2 as t}from"./chunks/framework.DZO5kRrk.js";const u=JSON.parse('{"title":"Flutter 2026 现代化实战 - 一个月学习规划表","description":"","frontmatter":{},"headers":[],"relativePath":"docs/flutter/learning-plan.md","filePath":"docs/flutter/learning-plan.md"}'),l={name:"docs/flutter/learning-plan.md"};function i(n,o,h,s,d,c){return a(),r("div",null,[...o[0]||(o[0]=[t('<h1 id="flutter-2026-现代化实战-一个月学习规划表" tabindex="-1">Flutter 2026 现代化实战 - 一个月学习规划表 <a class="header-anchor" href="#flutter-2026-现代化实战-一个月学习规划表" aria-label="Permalink to &quot;Flutter 2026 现代化实战 - 一个月学习规划表&quot;">​</a></h1><p><strong>目标</strong>：从零开始，使用现代化技术栈（Riverpod + GoRouter + MVVM）独立开发一个完整的 Flutter 应用。 <strong>时间投入</strong>：工作日 2 小时/天 (共 40 小时) + 周末 5 小时/天 (共 40 小时) ≈ <strong>80 小时</strong><strong>核心理念</strong>：不求快，求懂。每一行代码都要知道“为什么这么写”。</p><hr><h2 id="📅-第-1-周-地基、架构与第一个页面-约-20-小时" tabindex="-1">📅 第 1 周：地基、架构与第一个页面 (约 20 小时) <a class="header-anchor" href="#📅-第-1-周-地基、架构与第一个页面-约-20-小时" aria-label="Permalink to &quot;📅 第 1 周：地基、架构与第一个页面 (约 20 小时)&quot;">​</a></h2><h3 id="工作日-周一-环境配置与架构搭建-2h" tabindex="-1">[工作日] 周一：环境配置与架构搭建 (2h) <a class="header-anchor" href="#工作日-周一-环境配置与架构搭建-2h" aria-label="Permalink to &quot;[工作日] 周一：环境配置与架构搭建 (2h)&quot;">​</a></h3><ul><li>[ ] <strong>理解</strong>：搞懂 MVVM 与 Riverpod 的基本概念（阅读官方文档或我们的 LEARNING_GUIDE.md）。</li><li>[ ] <strong>实操</strong>：初始化项目，配置 <code>pubspec.yaml</code> (已完成)。</li><li>[ ] <strong>实操</strong>：建立规范的目录结构 (<code>lib/pages</code>, <code>lib/view_models</code> 等)。</li></ul><h3 id="工作日-周二-路由系统-gorouter-2h" tabindex="-1">[工作日] 周二：路由系统 GoRouter (2h) <a class="header-anchor" href="#工作日-周二-路由系统-gorouter-2h" aria-label="Permalink to &quot;[工作日] 周二：路由系统 GoRouter (2h)&quot;">​</a></h3><ul><li>[ ] <strong>理解</strong>：GoRouter 的页面栈管理原理。</li><li>[ ] <strong>实操</strong>：创建 <code>SplashPage</code> (闪屏页) 和 <code>LoginPage</code> (登录页) 的空壳。</li><li>[ ] <strong>实操</strong>：配置 <code>routers/app_router.dart</code>，实现从闪屏页自动跳到登录页。</li></ul><h3 id="工作日-周三-资源管理与屏幕适配-2h" tabindex="-1">[工作日] 周三：资源管理与屏幕适配 (2h) <a class="header-anchor" href="#工作日-周三-资源管理与屏幕适配-2h" aria-label="Permalink to &quot;[工作日] 周三：资源管理与屏幕适配 (2h)&quot;">​</a></h3><ul><li>[ ] <strong>工具</strong>：运行 <code>flutter_gen</code> 生成图片索引。</li><li>[ ] <strong>实操</strong>：配置 <code>flutter_screenutil</code>，确保 UI 在不同手机上不走样。</li><li>[ ] <strong>实操</strong>：在 <code>ThemeData</code> 里配置全局颜色和字体样式。</li></ul><h3 id="工作日-周四-widget-封装初体验-2h" tabindex="-1">[工作日] 周四：Widget 封装初体验 (2h) <a class="header-anchor" href="#工作日-周四-widget-封装初体验-2h" aria-label="Permalink to &quot;[工作日] 周四：Widget 封装初体验 (2h)&quot;">​</a></h3><ul><li>[ ] <strong>实操</strong>：封装一个通用的 <code>MyTextField</code> (输入框) 和 <code>MyButton</code> (按钮)。</li><li>[ ] <strong>重点</strong>：学习如何通过参数自定义组件样式，而不是复制粘贴代码。</li></ul><h3 id="工作日-周五-登录页-ui-实现-2h" tabindex="-1">[工作日] 周五：登录页 UI 实现 (2h) <a class="header-anchor" href="#工作日-周五-登录页-ui-实现-2h" aria-label="Permalink to &quot;[工作日] 周五：登录页 UI 实现 (2h)&quot;">​</a></h3><ul><li>[ ] <strong>实操</strong>：画出完整的登录页面 UI（Logo、输入框、按钮、底部协议）。</li><li>[ ] <strong>挑战</strong>：处理键盘弹出时遮挡输入框的问题。</li></ul><h3 id="周末-周六-riverpod-状态管理核心-5h" tabindex="-1">[周末] 周六：Riverpod 状态管理核心 (5h) <a class="header-anchor" href="#周末-周六-riverpod-状态管理核心-5h" aria-label="Permalink to &quot;[周末] 周六：Riverpod 状态管理核心 (5h)&quot;">​</a></h3><ul><li>[ ] <strong>深入</strong>：学习 <code>NotifierProvider</code> 和 <code>AsyncValue</code>。</li><li>[ ] <strong>实操</strong>：创建 <code>LoginViewModel</code>，模拟登录逻辑（点击按钮 -&gt; 转圈 -&gt; 成功/失败）。</li><li>[ ] <strong>实操</strong>：将 UI (View) 与 ViewModel 绑定，根据状态显示 Loading 或 错误提示。</li></ul><h3 id="周末-周日-第一周复盘与完善-5h" tabindex="-1">[周末] 周日：第一周复盘与完善 (5h) <a class="header-anchor" href="#周末-周日-第一周复盘与完善-5h" aria-label="Permalink to &quot;[周末] 周日：第一周复盘与完善 (5h)&quot;">​</a></h3><ul><li>[ ] <strong>实操</strong>：实现“密码可见/不可见”的小功能（使用 <code>flutter_hooks</code> 的 <code>useState</code>）。</li><li>[ ] <strong>复盘</strong>：检查代码是否符合 MVVM 规范，UI 中是否包含业务逻辑（不应该有）。</li><li>[ ] <strong>预习</strong>：下周要学的网络请求 Dio。</li></ul><hr><h2 id="📅-第-2-周-网络层与首页框架-约-20-小时" tabindex="-1">📅 第 2 周：网络层与首页框架 (约 20 小时) <a class="header-anchor" href="#📅-第-2-周-网络层与首页框架-约-20-小时" aria-label="Permalink to &quot;📅 第 2 周：网络层与首页框架 (约 20 小时)&quot;">​</a></h2><h3 id="工作日-周一-网络层封装-2h" tabindex="-1">[工作日] 周一：网络层封装 (2h) <a class="header-anchor" href="#工作日-周一-网络层封装-2h" aria-label="Permalink to &quot;[工作日] 周一：网络层封装 (2h)&quot;">​</a></h3><ul><li>[ ] <strong>实操</strong>：封装 Dio 单例，配置超时时间、BaseUrl。</li><li>[ ] <strong>实操</strong>：添加拦截器（Interceptor），统一打印请求日志。</li></ul><h3 id="工作日-周二-统一异常处理-2h" tabindex="-1">[工作日] 周二：统一异常处理 (2h) <a class="header-anchor" href="#工作日-周二-统一异常处理-2h" aria-label="Permalink to &quot;[工作日] 周二：统一异常处理 (2h)&quot;">​</a></h3><ul><li>[ ] <strong>实操</strong>：处理 401 (未登录)、500 (服务器错误) 等状态码。</li><li>[ ] <strong>实操</strong>：封装统一的 <code>APIResponse</code> 泛型类，解析后端返回的 <code>{ code, msg, data }</code> 结构。</li></ul><h3 id="工作日-周三-mock-数据与真实请求-2h" tabindex="-1">[工作日] 周三：Mock 数据与真实请求 (2h) <a class="header-anchor" href="#工作日-周三-mock-数据与真实请求-2h" aria-label="Permalink to &quot;[工作日] 周三：Mock 数据与真实请求 (2h)&quot;">​</a></h3><ul><li>[ ] <strong>实操</strong>：使用 <code>json_to_dart</code> 生成用户模型 (User Model)。</li><li>[ ] <strong>实操</strong>：将登录页的“模拟登录”替换为“真实请求”（可以使用 mock 接口）。</li></ul><h3 id="工作日-周四-首页底部通过-bottomnavigationbar-2h" tabindex="-1">[工作日] 周四：首页底部通过 (BottomNavigationBar) (2h) <a class="header-anchor" href="#工作日-周四-首页底部通过-bottomnavigationbar-2h" aria-label="Permalink to &quot;[工作日] 周四：首页底部通过 (BottomNavigationBar) (2h)&quot;">​</a></h3><ul><li>[ ] <strong>实操</strong>：创建 <code>MainPage</code>，使用 <code>Scaffold</code> 的 <code>bottomNavigationBar</code>。</li><li>[ ] <strong>实操</strong>：实现“首页”、“订单”、“我的”三个 Tab 的切换逻辑。</li></ul><h3 id="工作日-周五-首页-ui-搭建-2h" tabindex="-1">[工作日] 周五：首页 UI 搭建 (2h) <a class="header-anchor" href="#工作日-周五-首页-ui-搭建-2h" aria-label="Permalink to &quot;[工作日] 周五：首页 UI 搭建 (2h)&quot;">​</a></h3><ul><li>[ ] <strong>实操</strong>：学习 <code>Sliver</code> (CustomScrollView) 系列组件，实现复杂的滚动效果。</li><li>[ ] <strong>实操</strong>：实现首页的 Banner 轮播图。</li></ul><h3 id="周末-周六-复杂列表与分页-5h" tabindex="-1">[周末] 周六：复杂列表与分页 (5h) <a class="header-anchor" href="#周末-周六-复杂列表与分页-5h" aria-label="Permalink to &quot;[周末] 周六：复杂列表与分页 (5h)&quot;">​</a></h3><ul><li>[ ] <strong>难点</strong>：实现“上拉加载更多、下拉刷新” (SmartRefresher)。</li><li>[ ] <strong>实操</strong>：封装一个通用的 <code>PaginationViewModel</code>，处理分页逻辑。</li><li>[ ] <strong>实操</strong>：在首页列表应用这个通用逻辑。</li></ul><h3 id="周末-周日-本地存储与自动登录-5h" tabindex="-1">[周末] 周日：本地存储与自动登录 (5h) <a class="header-anchor" href="#周末-周日-本地存储与自动登录-5h" aria-label="Permalink to &quot;[周末] 周日：本地存储与自动登录 (5h)&quot;">​</a></h3><ul><li>[ ] <strong>实操</strong>：使用 <code>SharedPreferences</code> 保存登录 Token。</li><li>[ ] <strong>实操</strong>：改造 <code>SplashPage</code>，启动时检查 Token，自动决定跳登录页还是首页。</li><li>[ ] <strong>实操</strong>：实现“退出登录”功能，清理本地数据。</li></ul><hr><h2 id="📅-第-3-周-功能模块深耕-约-20-小时" tabindex="-1">📅 第 3 周：功能模块深耕 (约 20 小时) <a class="header-anchor" href="#📅-第-3-周-功能模块深耕-约-20-小时" aria-label="Permalink to &quot;📅 第 3 周：功能模块深耕 (约 20 小时)&quot;">​</a></h2><h3 id="工作日-周一-周三-订单模块-6h" tabindex="-1">[工作日] 周一 ~ 周三：订单模块 (6h) <a class="header-anchor" href="#工作日-周一-周三-订单模块-6h" aria-label="Permalink to &quot;[工作日] 周一 ~ 周三：订单模块 (6h)&quot;">​</a></h3><ul><li>[ ] <strong>实操</strong>：实现“订单列表”的多状态视图 (全部、待支付、已完成)。</li><li>[ ] <strong>实操</strong>：学习 Flutter 的 <code>TabView</code> 联动。</li><li>[ ] <strong>实操</strong>：订单详情页的传参跳转 (GoRouter 传递对象)。</li></ul><h3 id="工作日-周四-周五-个人中心与设置-4h" tabindex="-1">[工作日] 周四 ~ 周五：个人中心与设置 (4h) <a class="header-anchor" href="#工作日-周四-周五-个人中心与设置-4h" aria-label="Permalink to &quot;[工作日] 周四 ~ 周五：个人中心与设置 (4h)&quot;">​</a></h3><ul><li>[ ] <strong>实操</strong>：实现“我的”页面，列表项组件封装。</li><li>[ ] <strong>实操</strong>：夜间模式/多语言切换的实现原理（Provider 全局监听）。</li></ul><h3 id="周末-周六-周日-复杂交互与动画-10h" tabindex="-1">[周末] 周六 ~ 周日：复杂交互与动画 (10h) <a class="header-anchor" href="#周末-周六-周日-复杂交互与动画-10h" aria-label="Permalink to &quot;[周末] 周六 ~ 周日：复杂交互与动画 (10h)&quot;">​</a></h3><ul><li>[ ] <strong>挑战</strong>：给某些按钮添加 Hero 动画。</li><li>[ ] <strong>挑战</strong>：实现一个自定义的弹窗 (Dialog) 系统。</li><li>[ ] <strong>优化</strong>：使用 <code>flutter_img</code> 或 <code>cached_network_image</code> 优化图片加载体验。</li></ul><hr><h2 id="📅-第-4-周-查漏补缺与发布-约-20-小时" tabindex="-1">📅 第 4 周：查漏补缺与发布 (约 20 小时) <a class="header-anchor" href="#📅-第-4-周-查漏补缺与发布-约-20-小时" aria-label="Permalink to &quot;📅 第 4 周：查漏补缺与发布 (约 20 小时)&quot;">​</a></h2><h3 id="工作日-周一-周三-代码重构与优化-6h" tabindex="-1">[工作日] 周一 ~ 周三：代码重构与优化 (6h) <a class="header-anchor" href="#工作日-周一-周三-代码重构与优化-6h" aria-label="Permalink to &quot;[工作日] 周一 ~ 周三：代码重构与优化 (6h)&quot;">​</a></h3><ul><li>[ ] <strong>Code Review</strong>：自己检查代码，提取重复逻辑到 <code>common</code> 或 <code>utils</code>。</li><li>[ ] <strong>性能优化</strong>：使用 DevTools 查看是否存在重复 Build，优化 <code>const</code> 修饰符。</li></ul><h3 id="工作日-周四-周五-打包与发布-4h" tabindex="-1">[工作日] 周四 ~ 周五：打包与发布 (4h) <a class="header-anchor" href="#工作日-周四-周五-打包与发布-4h" aria-label="Permalink to &quot;[工作日] 周四 ~ 周五：打包与发布 (4h)&quot;">​</a></h3><ul><li>[ ] <strong>实操</strong>：通过 <code>flutter build apk</code> 和 <code>flutter build ios</code> 打包。</li><li>[ ] <strong>配置</strong>：修改 App 的名称、图标 (App Icon)。</li></ul><h3 id="周末-周六-周日-总结与扩展-10h" tabindex="-1">[周末] 周六 ~ 周日：总结与扩展 (10h) <a class="header-anchor" href="#周末-周六-周日-总结与扩展-10h" aria-label="Permalink to &quot;[周末] 周六 ~ 周日：总结与扩展 (10h)&quot;">​</a></h3><ul><li>[ ] <strong>文档</strong>：给自己的项目写一个 <code>README.md</code>。</li><li>[ ] <strong>扩展</strong>：尝试引入一个新的库（比如图表库 fl_chart）并集成进去。</li><li>[ ] <strong>庆祝</strong>：奖励自己一顿大餐！🎉</li></ul><hr><h3 id="🔥-你的当前进度-第-1-周-周一" tabindex="-1">🔥 你的当前进度：第 1 周 / 周一 <a class="header-anchor" href="#🔥-你的当前进度-第-1-周-周一" aria-label="Permalink to &quot;🔥 你的当前进度：第 1 周 / 周一&quot;">​</a></h3><p><strong>任务</strong>：</p><ol><li>[x] 创建 <code>pubspec.yaml</code></li><li>[ ] 执行 <code>flutter pub get</code> (上一步被取消了，记得手动运行)</li><li>[ ] 创建 MVVM 目录结构 (下一步要做这个)</li></ol>',54)])])}const b=e(l,[["render",i]]);export{u as __pageData,b as default};
